parameters.schemaJson:
[
  {
    "name": "customer_name",
    "type": "TEXT",
    "description": "Name of the customer or buying company"
  },
  {
    "name": "po_number",
    "type": "TEXT",
    "description": "Purchase order number"
  },
  {
    "name": "po_date",
    "type": "DATE",
    "description": "Date the PO was issued"
  },
  {
    "name": "requested_delivery_date",
    "type": "DATE",
    "description": "Requested delivery date"
  },
  {
    "name": "billing_address",
    "type": "TEXT",
    "description": "Customer billing address"
  },
  {
    "name": "shipping_address",
    "type": "TEXT",
    "description": "Delivery address"
  },
  {
    "name": "line_items",
    "type": "ARRAY",
    "description": "Individual line items on the purchase order",
    "children": [
      {
        "name": "product_sku",
        "type": "TEXT",
        "description": "Product SKU or item code"
      },
      {
        "name": "product_name",
        "type": "TEXT",
        "description": "Product name or description"
      },
      {
        "name": "quantity",
        "type": "INTEGER",
        "description": "Quantity ordered"
      },
      {
        "name": "unit_price",
        "type": "CURRENCY_AMOUNT",
        "description": "Price per unit"
      },
      {
        "name": "line_total",
        "type": "CURRENCY_AMOUNT",
        "description": "Total for this line item"
      }
    ]
  },
  {
    "name": "currency",
    "type": "CURRENCY_CODE",
    "description": "Order currency"
  },
  {
    "name": "po_total",
    "type": "CURRENCY_AMOUNT",
    "description": "Total order value"
  }
]

parameters.documentJson:
{
  "metadata": {
    "title": "Order Confirmation — {{ $json.po_number }}",
    "author": "Meridian Manufacturing Co."
  },
  "page": {
    "size": { "preset": "A4" },
    "margins": {
      "top_in_pt": 54,
      "right_in_pt": 54,
      "bottom_in_pt": 54,
      "left_in_pt": 54
    }
  },
  "content": [
    { "type": "headline", "level": "h1", "text": "Meridian Manufacturing Co." },
    { "type": "paragraph", "runs": [{ "text": "1840 Industrial Parkway\nColumbus, OH 43201\norders@meridian-mfg.com" }] },
    { "type": "separator" },
    { "type": "headline", "level": "h2", "text": "Order Confirmation" },
    {
      "type": "paragraph",
      "runs": [
        { "text": "Order confirmed for: ", "font_weight": "bold" },
        { "text": "{{ $json.customer_name }}\n" },
        { "text": "PO Number: ", "font_weight": "bold" },
        { "text": "{{ $json.po_number }}\n" },
        { "text": "PO Date: ", "font_weight": "bold" },
        { "text": "{{ $json.po_date }}\n" },
        { "text": "Estimated Delivery: ", "font_weight": "bold" },
        { "text": "{{ $json.requested_delivery_date }}" }
      ]
    },
    {
      "type": "table",
      "headers": [
        { "text": "SKU" },
        { "text": "Product" },
        { "text": "Qty" },
        { "text": "Unit Price" },
        { "text": "Line Total" }
      ],
      "rows": "{{ $json.line_items }}"
    },
    { "type": "separator" },
    {
      "type": "paragraph",
      "runs": [{ "text": "Order Total: {{ $json.currency }} {{ $json.po_total }}", "font_weight": "bold" }]
    },
    { "type": "paragraph", "runs": [{ "text": "Questions? Contact orders@meridian-mfg.com" }] }
  ]
}
